# App.View.PostsView

defmodule App.View.PostsView do
  use Phoenix.LiveView

  def render(assigns) do
    post = assigns[:post]

    html do
      div do
        h1(post.title)
        div(class: "post-content") do
          raw(post.content)
        end
      end
    end
  end
end